package com.agmsolutions.fabrick_test.exceptions;import com.agmsolutions.fabrick_test.Model.dto.ErrorResponseDto;import com.agmsolutions.fabrick_test.Model.dto.FabrickErrorDetailDto;import com.agmsolutions.fabrick_test.Model.dto.FabrickErrorDto;import lombok.extern.slf4j.Slf4j;import org.apache.coyote.BadRequestException;import org.springframework.http.ResponseEntity;import org.springframework.http.converter.HttpMessageNotReadableException;import org.springframework.web.bind.MethodArgumentNotValidException;import org.springframework.web.bind.MissingServletRequestParameterException;import org.springframework.web.bind.annotation.ExceptionHandler;import org.springframework.web.bind.annotation.RestControllerAdvice;import org.springframework.web.client.HttpClientErrorException;import org.springframework.web.client.ResourceAccessException;import org.springframework.web.method.annotation.MethodArgumentTypeMismatchException;import tools.jackson.databind.ObjectMapper;import java.time.LocalDateTime;import java.util.List;@RestControllerAdvice@Slf4jpublic class GlobalExceptionHandler {    @ExceptionHandler(HttpClientErrorException.class)    public ResponseEntity<ErrorResponseDto> handleFabrickApiError(HttpClientErrorException ex) {        String message="Errore chiamata Fabrick";                try {            ObjectMapper mapper = new ObjectMapper();            FabrickErrorDto fabrickError = mapper.readValue(                    ex.getResponseBodyAsString(), FabrickErrorDto.class            );            if (fabrickError.getErrors() != null && !fabrickError.getErrors().isEmpty()) {                List<String> errors= fabrickError.getErrors().stream().map(FabrickErrorDetailDto::getDescription).toList();                return buildResponseMultipleErrors(ex.getStatusCode().value(),  message, errors);            }                    } catch (Exception e) {            message += ": " + ex.getMessage();        }                return buildResponse(ex.getStatusCode().value(),  message);    }    @ExceptionHandler(Exception.class)    public ResponseEntity<ErrorResponseDto> handleGenericError(Exception ex) {        return buildResponse(500, "Errore interno del server");    }    @ExceptionHandler(ResourceAccessException.class)    public ResponseEntity<ErrorResponseDto> handleConnectionError(ResourceAccessException ex) {        return buildResponse(503, "Servizio Fabrick non disponibile");    }    @ExceptionHandler(BadRequestException.class)    public ResponseEntity<ErrorResponseDto> handleBadRequest(BadRequestException ex) {        return buildResponse(400, "Bad Request: "+ ex.getMessage());    }    @ExceptionHandler(MethodArgumentNotValidException.class)    public ResponseEntity<ErrorResponseDto> handleValidation(MethodArgumentNotValidException ex) {                List<String> errors = ex.getBindingResult().getFieldErrors()                .stream()                .map(e -> e.getField() + ": " + e.getDefaultMessage())                .toList();                return buildResponseMultipleErrors(400, "Errore di validazione", errors);    }    @ExceptionHandler(MissingServletRequestParameterException.class)    public ResponseEntity<ErrorResponseDto> handleMissingParam(MissingServletRequestParameterException ex) {        return buildResponse(400, "Parametro obbligatorio mancante: " + ex.getParameterName());    }    @ExceptionHandler(MethodArgumentTypeMismatchException.class)    public ResponseEntity<ErrorResponseDto> handleTypeMismatch(MethodArgumentTypeMismatchException ex) {        String message = String.format(                "Formato non valido per il parametro '%s': valore '%s' non convertibile in %s",                ex.getName(),                ex.getValue(),                ex.getRequiredType() != null ? ex.getRequiredType().getSimpleName() : "tipo sconosciuto"        );        return buildResponse(400, message);    }    @ExceptionHandler(HttpMessageNotReadableException.class)    public ResponseEntity<ErrorResponseDto> handleInvalidFormat(HttpMessageNotReadableException ex) {        return buildResponse(400, "Body non valido o malformato: " + ex.getMostSpecificCause().getMessage());    }    private ResponseEntity<ErrorResponseDto> buildResponse(int status, String message) {        ErrorResponseDto body = ErrorResponseDto.builder()                .status(status)                .message(message)                .timestamp(LocalDateTime.now())                .build();        log.error("ERROR {} {} - {}", status, body.getTimestamp(), message);        return ResponseEntity.status(status).body(body);    }        private ResponseEntity<ErrorResponseDto> buildResponseMultipleErrors(int status, String message, List<String> errors) {        ErrorResponseDto body = ErrorResponseDto.builder()                .status(status)                .message(message)                .errors(errors)                .timestamp(LocalDateTime.now())                .build();        log.error("ERROR {} {} - {} - {}", status, body.getTimestamp(), message, errors);        return ResponseEntity.status(status).body(body);    }    }